function detectAnomalies(samples, def) {
  if (isBooleanTag(def.slug)) return [];
  const anomalies = [];
  let inBreach = false;
  for (const sample of samples) {
    const breach = breachForValue(def, sample.value);
    if (breach && !inBreach) {
      anomalies.push({ ts: sample.ts, reason: 'entered threshold' });
      inBreach = true;
    } else if (!breach && inBreach) {
      inBreach = false;
    }
  }
  return anomalies;
}

