function classifyQuery(msg: string): QueryClass {
  const m = msg.toLowerCase();
  if (/\b(production|meter|gsm)\b/.test(m)) return "production";
  if (/\b(yesterday|last hour|last \d)\b/.test(m)) return "historical";
  if (/\b(current|live|now|status)\b/.test(m)) return "current";
  return "current";
}

function downsampleSeries(data: { x: string; y: number }[], maxPoints = 500) {
  if (data.length <= maxPoints) return data;
  const bucketSize = Math.ceil(data.length / maxPoints);
  const result = [data[0]!];
  for (let i = 1; i < data.length - 1; i += bucketSize) {
    const bucket = data.slice(i, Math.min(i + bucketSize, data.length - 1));
    const avgY = bucket.reduce((s, p) => s + p.y, 0) / bucket.length;
    result.push({ x: bucket[Math.floor(bucket.length / 2)].x, y: avgY });
  }
  result.push(data[data.length - 1]!);
  return result;
}

function normalizeSchema(input: unknown): Record<string, unknown> {
  if (!input || typeof input !== "object") return {};
  const raw = input as Record<string, unknown>;
  const out: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(raw)) {
    if (key === "properties") {
      out[key] = Object.fromEntries(Object.entries(value).map(([k, v]) => [k, normalizeSchema(v)]));
      continue;
    }
    if (key === "items") {
      out[key] = normalizeSchema(value);
      continue;
    }
    out[key] = value;
  }
  return out;
}

export function toBedrockMessages(history: BedrockChatMessage[], userMessage: string): Message[] {
  const mapped: Message[] = history
    .filter((m) => m.role !== "system")
    .map((m) => ({ role: m.role === "assistant" ? "assistant" : "user", content: [{ text: m.content }] }));

  const normalized: Message[] = [];
  for (const item of mapped) {
    const previous = normalized[normalized.length - 1];
    if (previous && previous.role === item.role) {
      previous.content.push(...item.content);
      continue;
    }
    normalized.push(item);
  }
  normalized.push({ role: "user", content: [{ text: userMessage }] });
  return normalized;
}

async function buildTrendData(machineId: string, windowStart: Date, windowEnd: Date) {
  const samples = await prisma.tagSample.findMany({
    where: { machineId, ts: { gte: windowStart, lte: windowEnd } },
    take: 10_000
  });
  const byTag = new Map<string, number[]>();
  for (const s of samples) {
    const arr = byTag.get(s.tagId) ?? [];
    arr.push(s.valueNumber);
    byTag.set(s.tagId, arr);
  }
  return defs.map(def => ({
    slug: def.slug, 
    ...summarizeNumbers(byTag.get(def.tagId) ?? []) 
  }));
}

async function runBedrockPipeline(args: AgentArgs) {
  for (let round = 0; round < 8; round++) {
    const response = await bedrockConverse({ messages, tools, ... });
    const toolUses = extractToolUses(response.content);
    if (!toolUses.length) return { reply: extractText(response.content) };

    const toolResults = await Promise.all(toolUses.map(use => runTool(use)));
    messages.push({ role: "assistant", content: response.content });
    messages.push({ role: "user", content: toolResults });
  }
}

